class PostsSearch{constructor(){this.searchInput=document.getElementById("search-input"),this.searchIcon=document.getElementById("search-icon"),this.searchInput.onkeyup=s=>{"Enter"===s.key&&this.searchPosts()},this.searchIcon.onclick=()=>{this.searchPosts()}}searchPosts(){if(this.searchInput.value){let s=new URLSearchParams;s.set("tags",this.searchInput.value),location.href=`/posts/?${s.toString()}`}}}export{PostsSearch};